mapper.select:
select 
from pt_coach_schedule sc

    AND sc.coach_id = #{coachId}
    AND sc.store_id = #{storeId}
    AND sc.weekday = #{weekday}
    AND sc.is_enabled = #{isEnabled}
    AND sc.store_id in (${storeIds})

order by sc.coach_id asc, sc.weekday asc, sc.start_time asc

    limit #{offset}, #{limit}

select count(*) from pt_coach_schedule sc

    AND sc.coach_id = #{coachId}
    AND sc.store_id = #{storeId}
    AND sc.weekday = #{weekday}
    AND sc.is_enabled = #{isEnabled}
    AND sc.store_id in (${storeIds})

select count(*) from pt_coach_schedule
where coach_id = #{coachId} and store_id = #{storeId} and weekday = #{weekday}
  and is_enabled = 1
  and start_time < #{endTime} and end_time > #{startTime}
AND id <> #{excludeId}
